## Was in App.tsx zu tun ist

Datei: app-mock-react/src/App.tsx

### 1. Neuen Import hinzufügen
```tsx
import SetPasswordScreen from './screens/SetPasswordScreen';
```

### 2. State für pending tokens (tokens die auf Passwort warten)
Keinen neuen State nötig - die tokens werden in handlePasswordRequired gespeichert und screen auf 'set-password' gesetzt. Der bestehende tokens-State wird genutzt.

### 3. Neue Handler-Funktionen hinzufügen
```tsx
function handlePasswordRequired(t: OidcTokens) {
  setTokens(t);
  setAutoLogin(false);
  setScreen('set-password');
  log('Passwort-Einrichtung erforderlich.', 'warn');
}

function handlePasswordSet(t: OidcTokens) {
  setScreen('authenticated');
  log('Passwort gesetzt, angemeldet.', 'ok');
}
```

### 4. HomeScreen-Verwendung anpassen (Zeile 116-124)
onPasswordRequired-Prop hinzufügen:
```tsx
{screen === 'home' && binding && privateKey && (
  <HomeScreen
    binding={binding}
    privateKey={privateKey}
    onLoggedIn={handleLoggedIn}
    onPasswordRequired={handlePasswordRequired}
    onUnregister={handleUnregister}
    log={log}
    autoLogin={autoLogin}
  />
)}
```

### 5. Neuen Screen-Block für 'set-password' einfügen (zwischen 'home' und 'authenticated')
```tsx
{screen === 'set-password' && tokens && (
  <SetPasswordScreen
    tokens={tokens}
    onPasswordSet={handlePasswordSet}
    log={log}
  />
)}
```

