export async function getPendingConsent(accessToken: string): Promise<PushConsentRequest | null> {
  const resp = await fetch(`${AUTH_SERVICE_URL}/api/v1/push-consent/pending`, {
    headers: { Authorization: `Bearer ${accessToken}` },
  });
