export async function resolveConsent(accessToken: string, requestId: string, approved: boolean): Promise<void> {
  const resp = await fetch(`${AUTH_SERVICE_URL}/api/v1/push-consent/${requestId}/resolve`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${accessToken}`,
