## Schritt 3: ConsentScreen.tsx erstellen
Datei: app-mock-react/src/screens/ConsentScreen.tsx (neue Datei)

Die Komponente empfängt Tokens (OidcTokens), onApproved() und onDenied() und onLogout() als Props.
Sie pollt alle 2 Sekunden getPendingConsent(). Wenn eine ausstehende Anfrage vorliegt, zeigt sie diese an.
Wenn keine Anfrage vorliegt (z.B. noch nicht erstellt), zeigt sie einen Ladezustand.
Wenn die Anfrage abgelaufen ist (expiresAt in der Vergangenheit), zeigt sie einen Timeout-Fehler.

```typescript
import { useState, useEffect, useRef } from 'react';
import { getPendingConsent, resolveConsent } from '../services/api';
import { Spinner } from '../components/ui';
import type { OidcTokens, LogEntry, PushConsentRequest } from '../types';

interface Props {
  tokens: OidcTokens;
  onApproved: () => void;
  onDenied: () => void;
  onLogout: () => void;
  log: (msg: string, level?: LogEntry['level']) => void;
}

export default function ConsentScreen({ tokens, onApproved, onDenied, onLogout, log }: Props) {
  const [request, setRequest]   = useState<PushConsentRequest | null>(null);
  const [busy, setBusy]         = useState(false);
  const [error, setError]       = useState('');
  const intervalRef             = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    // Poll every 2 seconds for a pending consent request
    intervalRef.current = setInterval(async () => {
      try {
        const pending = await getPendingConsent(tokens.access_token);
        setRequest(pending);
      } catch (err) {
        setError((err as Error).message);
      }
    }, 2000);
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [tokens.access_token]);

  async function handleApprove() {
    if (!request || busy) return;
    setBusy(true);
    try {
      await resolveConsent(tokens.access_token, request.requestId, true);
      log('Consent erteilt.', 'ok');
      onApproved();
    } catch (err) {
      setError((err as Error).message);
      log(`Consent fehlgeschlagen: ${(err as Error).message}`, 'err');
    } finally {
      setBusy(false);
    }
  }

  async function handleDeny() {
    if (!request || busy) return;
    setBusy(true);
    try {
      await resolveConsent(tokens.access_token, request.requestId, false);
      log('Consent verweigert.', 'warn');
      onDenied();
    } catch (err) {
      setError((err as Error).message);
      log(`Consent fehlgeschlagen: ${(err as Error).message}`, 'err');
    } finally {
      setBusy(false);
    }
  }

  const isExpired = request ? new Date(request.expiresAt) < new Date() : false;

  return (
    <div className="flex flex-col gap-6">
      <div className="text-center pt-4 flex flex-col items-center">
        <div className="w-16 h-16 rounded-full bg-[--color-accent]/20 flex items-center justify-center text-4xl mb-3 leading-none">
          🔔
        </div>
        <h2 className="text-xl font-bold">Login bestätigen</h2>
        <p className="text-sm text-[--color-text-dim] mt-1">
          Ein Gerät möchte sich mit deinem Konto anmelden.
        </p>
      </div>

      {error && <p className="text-sm text-red-400 text-center">{error}</p>}

      {!request && !error && (
        <div className="flex items-center justify-center gap-2 text-sm text-[--color-text-dim]">
          <Spinner size="md" /> Warte auf Anfrage…
        </div>
      )}

      {request && !isExpired && (
        <div className="bg-[--color-bg] border border-[--color-border] rounded-xl p-4 text-sm">
          <p className="text-[--color-text-dim]">Anfrage-ID: <span className="font-mono text-[--color-accent]">{request.requestId.slice(0, 8)}…</span></p>
          <p className="text-[--color-text-dim] mt-1">Gültig bis: {new Date(request.expiresAt).toLocaleTimeString('de-DE')}</p>
        </div>
      )}

      {isExpired && (
        <p className="text-sm text-red-400 text-center">Anfrage abgelaufen.</p>
      )}

      <div className="flex gap-3">
        <button
          className="btn-primary flex-1"
          onClick={handleApprove}
          disabled={busy || !request || isExpired}
        >
          {busy ? <><Spinner /> Bestätige…</> : '✅ Zustimmen'}
        </button>
        <button
          className="btn-danger"
          onClick={handleDeny}
          disabled={busy || !request || isExpired}
        >
          ❌ Ablehnen
        </button>
      </div>

      <button className="text-xs text-[--color-text-dim] hover:text-[--color-text] transition-colors text-center" onClick={onLogout}>
        Abmelden
      </button>
    </div>
  );
}
```

