## Neue Methoden im AuthServiceClient (e2e/helpers/client.ts)
Folgende Methoden müssen zur AuthServiceClient-Klasse hinzugefügt werden:

```typescript
// Interfaces ergänzen:
export interface CreatePushConsentRequest {
  userId: string;
  sessionId: string;
  ttlSeconds: number;
}

export interface PushConsentRequestResponse {
  requestId: string;
  expiresAt: string;
}

export interface PushConsentPendingResponse {
  requestId: string;
  userId: string;
  expiresAt: string;
}

export interface PushConsentStatusResponse {
  status: 'PENDING' | 'APPROVED' | 'DENIED';
}

// Methoden in AuthServiceClient:
async createPushConsentRequest(
  req: CreatePushConsentRequest
): Promise<HttpResponse<PushConsentRequestResponse>> {
  // HTTP Basic Auth: KEYCLOAK_ADMIN / KEYCLOAK_ADMIN_PASSWORD aus ENV
  const username = process.env['KEYCLOAK_ADMIN'] ?? 'admin';
  const password = process.env['KEYCLOAK_ADMIN_PASSWORD'] ?? 'admin-password';
  const creds = Buffer.from(`${username}:${password}`).toString('base64');
  return request<PushConsentRequestResponse>(
    'POST',
    `${this.base}/api/v1/push-consent/request`,
    req,
    { Authorization: `Basic ${creds}` }
  );
}

async getPendingConsent(
  accessToken: string
): Promise<HttpResponse<PushConsentPendingResponse | null>> {
  return request<PushConsentPendingResponse | null>(
    'GET',
    `${this.base}/api/v1/push-consent/pending`,
    undefined,
    { Authorization: `Bearer ${accessToken}` }
  );
}

async resolveConsent(
  accessToken: string,
  requestId: string,
  approved: boolean
): Promise<HttpResponse<{ status: string }>> {
  return request<{ status: string }>(
    'POST',
    `${this.base}/api/v1/push-consent/${requestId}/resolve`,
    { approved },
    { Authorization: `Bearer ${accessToken}` }
  );
}

async getPushConsentStatus(
  sessionId: string
): Promise<HttpResponse<PushConsentStatusResponse>> {
  const username = process.env['KEYCLOAK_ADMIN'] ?? 'admin';
  const password = process.env['KEYCLOAK_ADMIN_PASSWORD'] ?? 'admin-password';
  const creds = Buffer.from(`${username}:${password}`).toString('base64');
  return request<PushConsentStatusResponse>(
    'GET',
    `${this.base}/api/v1/push-consent/${sessionId}/status`,
    undefined,
    { Authorization: `Basic ${creds}` }
  );
}
```

