package dev.authsandbox.authservice.service;

import dev.authsandbox.authservice.dto.*;
import dev.authsandbox.authservice.entity.PushConsentRequest;
import dev.authsandbox.authservice.repository.DeviceRepository;
import dev.authsandbox.authservice.repository.PushConsentRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.OffsetDateTime;
import java.util.NoSuchElementException;
import java.util.Optional;
import java.util.UUID;

@Service
@RequiredArgsConstructor
@Slf4j
public class PushConsentService {

    private final PushConsentRepository pushConsentRepository;
    private final DeviceRepository deviceRepository;

    /** Erstellt eine neue Consent-Anfrage (aufgerufen von Keycloak-SPI via HTTP Basic) */
    @Transactional
    public CreatePushConsentResponse createRequest(CreatePushConsentRequest req) {
        // Alte PENDING-Anfragen für diesen User löschen (cleanup)
        pushConsentRepository.findFirstByUserIdAndStatusOrderByCreatedAtDesc(
            req.userId(), PushConsentRequest.Status.PENDING)
            .ifPresent(old -> {
                old.setStatus(PushConsentRequest.Status.DENIED);
                pushConsentRepository.save(old);
            });

        OffsetDateTime expiresAt = OffsetDateTime.now().plusSeconds(req.ttlSeconds());
        PushConsentRequest entity = PushConsentRequest.builder()
            .userId(req.userId())
            .sessionId(req.sessionId())
            .status(PushConsentRequest.Status.PENDING)
            .expiresAt(expiresAt)
            .build();
        pushConsentRepository.save(entity);
        log.info("Created push consent request {} for user {}", entity.getId(), req.userId());
        return new CreatePushConsentResponse(entity.getId(), expiresAt);
    }

    /** App fragt ab: hat mein User eine ausstehende Consent-Anfrage? */
    @Transactional(readOnly = true)
    public Optional<PushConsentPendingResponse> getPending(String userId) {
        return pushConsentRepository.findFirstByUserIdAndStatusOrderByCreatedAtDesc(
            userId, PushConsentRequest.Status.PENDING)
            .filter(r -> r.getExpiresAt().isAfter(OffsetDateTime.now()))
            .map(r -> new PushConsentPendingResponse(r.getId(), r.getUserId(), r.getExpiresAt()));
    }

    /** App erteilt oder verweigert Zustimmung */
    @Transactional
    public ResolvePushConsentResponse resolve(UUID requestId, String userId, boolean approved) {
        PushConsentRequest request = pushConsentRepository.findById(requestId)
            .orElseThrow(() -> new NoSuchElementException("Consent request not found: " + requestId));

        if (!request.getUserId().equals(userId)) {
            throw new IllegalArgumentException("Not authorized to resolve this request");
        }
        if (request.getStatus() != PushConsentRequest.Status.PENDING) {
            throw new IllegalStateException("Request already resolved: " + request.getStatus());
        }
        if (request.getExpiresAt().isBefore(OffsetDateTime.now())) {
            throw new IllegalStateException("Request expired");
        }

        request.setStatus(approved ? PushConsentRequest.Status.APPROVED : PushConsentRequest.Status.DENIED);
        pushConsentRepository.save(request);
        log.info("Resolved push consent request {} as {}", requestId, request.getStatus());
        return new ResolvePushConsentResponse(request.getStatus().name());
    }

    /** Keycloak-SPI fragt Status ab (per sessionId) */
    @Transactional(readOnly = true)
    public PushConsentStatusResponse getStatus(String sessionId) {
        PushConsentRequest request = pushConsentRepository.findBySessionId(sessionId)
            .orElseThrow(() -> new NoSuchElementException("No consent request for session: " + sessionId));

        // Wenn noch PENDING und abgelaufen → als DENIED behandeln
        if (request.getStatus() == PushConsentRequest.Status.PENDING &&
            request.getExpiresAt().isBefore(OffsetDateTime.now())) {
            return new PushConsentStatusResponse("DENIED");
        }
        return new PushConsentStatusResponse(request.getStatus().name());
    }

    /** Cleanup: abgelaufene Anfragen löschen (alle 5 Minuten) */
    @Scheduled(fixedDelay = 300_000)
    @Transactional
    public void cleanupExpired() {
        pushConsentRepository.deleteExpired(OffsetDateTime.now());
    }
}
```

### 4. controller/PushConsentController.java (neue Datei)
```java
package dev.authsandbox.authservice.controller;

import dev.authsandbox.authservice.dto.*;
import dev.authsandbox.authservice.service.PushConsentService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.web.bind.annotation.*;

import java.util.NoSuchElementException;
import java.util.UUID;

@RestController
@RequestMapping("/api/v1/push-consent")
@RequiredArgsConstructor
public class PushConsentController {

    private final PushConsentService pushConsentService;

    /** POST /api/v1/push-consent/request — HTTP Basic (Keycloak SPI) */
    @PostMapping("/request")
    public ResponseEntity<CreatePushConsentResponse> createRequest(
            @Valid @RequestBody CreatePushConsentRequest request) {
        CreatePushConsentResponse response = pushConsentService.createRequest(request);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    /** GET /api/v1/push-consent/pending — Bearer Token (App) */
    @GetMapping("/pending")
    public ResponseEntity<PushConsentPendingResponse> getPending(
            @AuthenticationPrincipal Jwt jwt) {
        String userId = jwt.getClaimAsString("preferred_username");
        return pushConsentService.getPending(userId)
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.noContent().build());
    }

    /** POST /api/v1/push-consent/{requestId}/resolve — Bearer Token (App) */
    @PostMapping("/{requestId}/resolve")
    public ResponseEntity<ResolvePushConsentResponse> resolve(
            @PathVariable UUID requestId,
            @RequestBody ResolvePushConsentRequest request,
            @AuthenticationPrincipal Jwt jwt) {
        String userId = jwt.getClaimAsString("preferred_username");
        try {
            ResolvePushConsentResponse response = pushConsentService.resolve(requestId, userId, request.approved());
            return ResponseEntity.ok(response);
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        } catch (IllegalArgumentException e) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        } catch (IllegalStateException e) {
            return ResponseEntity.status(HttpStatus.CONFLICT).build();
        }
    }

    /** GET /api/v1/push-consent/{sessionId}/status — HTTP Basic (Keycloak SPI) */
    @GetMapping("/{sessionId}/status")
    public ResponseEntity<PushConsentStatusResponse> getStatus(
            @PathVariable String sessionId) {
        try {
            PushConsentStatusResponse response = pushConsentService.getStatus(sessionId);
            return ResponseEntity.ok(response);
        } catch (NoSuchElementException e) {
            return ResponseEntity.notFound().build();
        }
    }
}
```

### 5. SecurityConfig.java anpassen
Datei: config/SecurityConfig.java

Die .authorizeHttpRequests()-Konfiguration muss um Push-Consent-Routen ergänzt werden.

Die internen Endpoints (POST /request, GET /{sessionId}/status) sollen HTTP Basic gesichert sein (gleiche Credentials wie /api/v1/admin/**).
Die App-Endpoints (GET /pending, POST /{requestId}/resolve) sollen Bearer-Token-gesichert sein.

Da SecurityConfig.java bereits HTTP Basic für /api/v1/admin/** über Spring Security's inMemory-User hat (application.yaml: spring.security.user.name/password), genügt es, /api/v1/push-consent/request und /api/v1/push-consent/*/status dem gleichen Basic-Auth-Schutz zuzuordnen.

Wichtig: Die zwei Endpoint-Typen brauchen unterschiedliche Authentifizierung in derselben FilterChain. Einfachste Lösung: ALLE /api/v1/push-consent/** über .authenticated() absichern — sowohl Basic Auth als auch Bearer Token funktionieren dann.

Ändere in SecurityConfig.java die requestMatchers-Konfiguration:
```java
.authorizeHttpRequests(auth -> auth
    .requestMatchers(
        "/api/v1/devices/**",
        "/api/v1/auth/**",
        "/api/v1/transfer/**",
        "/api/v1/users/me/**",
        "/p/**",
        "/cms/**",
        "/actuator/health",
        "/actuator/info"
    ).permitAll()
    .requestMatchers("/api/v1/admin/**", "/api/v1/cms/**", "/api/v1/push-consent/**").authenticated()
    .anyRequest().authenticated()
)
```

Außerdem muss httpBasic() aktiviert werden (derzeit nur oauth2ResourceServer):
```java
.httpBasic(Customizer.withDefaults())
.oauth2ResourceServer(oauth2 -> oauth2.jwt(jwt -> {}))
```

